# The circuit creates a GHZ-like state where the parity of the first 3 bits
# must match the 4th bit (state = sum_{x \in {0,1}^3} |x, x_0 ^ x_1 ^ x_2> / sqrt(8))
valid_outcomes = {
    state for state in counts 
    if (int(state[0]) ^ int(state[1]) ^ int(state[2])) == int(state[3])
}

assert len(valid_outcomes) == len(counts), "Measured outcome violates parity constraint"
assert len(counts) >= 4, "Support collapsed to too few outcomes"
